export const createGroup = createAsyncThunk(
  'groups/create',
  async ({ name, description, isPrivate = false }, { rejectWithValue }) => {
    try {
      const response = await groupService.createGroup({ name, description, isPrivate });
      const data = response.data?.data || response.data;
      // Auto add self as admin
      if (data?.Data?.groupId || data?.groupId || data?._id) {
        const groupId = data.Data?.groupId || data.groupId || data._id;
        try {
          await groupService.addGroupAdmin({ groupId });
        } catch (e) {
          // Non-critical
        }
      }
      return data;
    } catch (error) {
      return rejectWithValue(error.response?.data?.message || 'Failed to create group');
    }
  }
);

