import React from 'react';
import { useSelector } from 'react-redux';
import { useNavigate, useLocation } from 'react-router-dom';
import './BottomNav.css';

const BottomNav = () => {
  const { isAuthenticated } = useSelector((state) => state.auth);
  const { unreadCount: chatUnread } = useSelector((state) => state.chat);
  const { unreadCount: notifUnread } = useSelector((state) => state.notifications);
  const navigate = useNavigate();
  const location = useLocation();

  // Hide on auth pages
  const authPaths = ['/login', '/register', '/forgot-password'];
  if (authPaths.includes(location.pathname)) return null;
  if (!isAuthenticated) return null;

  const tabs = [
    { path: '/', label: 'Home', icon: '🏠' },
    { path: '/friends', label: 'Friends', icon: '👥' },
    { path: '/messages', label: 'Messages', icon: '💬', badge: chatUnread },
    { path: '/notifications', label: 'Alerts', icon: '🔔', badge: notifUnread },
    { path: '/profile', label: 'Profile', icon: '👤' },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <div className="bottom-nav">
      {tabs.map((tab) => (
        <button
          key={tab.path}
          className={`bottom-nav-tab ${isActive(tab.path) ? 'active' : ''}`}
          onClick={() => navigate(tab.path)}
        >
          <span className="bottom-nav-icon">{tab.icon}</span>
          <span className="bottom-nav-label">{tab.label}</span>
          {tab.badge > 0 && <span className="bottom-nav-badge">{tab.badge}</span>}
        </button>
      ))}
    </div>
  );
};

export default BottomNav;
