import { nodeApi, dotnetApi } from '../axios';
import { ENDPOINTS } from '../config';

const postService = {
  createPost: (formData) => nodeApi.post(ENDPOINTS.CREATE_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  getMyPosts: (params) => nodeApi.get(ENDPOINTS.GET_MY_POSTS, { params }),
  deletePost: (data) => nodeApi.post(ENDPOINTS.DELETE_POST, data),
  editPost: (formData) => nodeApi.post(ENDPOINTS.EDIT_POST, formData, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  getPostDetail: (params) => nodeApi.get(ENDPOINTS.POST_DETAIL, { params }),
  getOtherUserPosts: (params) => nodeApi.get(ENDPOINTS.GET_OTHER_POSTS, { params }),
  getFriendsPosts: (params) => nodeApi.get(ENDPOINTS.GET_FRIENDS_POSTS, { params }),
  getPublicPosts: (params) => dotnetApi.get(ENDPOINTS.PUBLIC_POSTS, { params }),
  sharePost: (data) => dotnetApi.post(ENDPOINTS.SHARE_POST, data),
  likeUnlike: (data) => nodeApi.post(ENDPOINTS.LIKE_UNLIKE, data),
  dislike: (data) => nodeApi.post(ENDPOINTS.DISLIKE, data),
  updateSensitivity: (data) => dotnetApi.post(ENDPOINTS.UPDATE_SENSITIVITY, data),
  commentOnOff: (data) => nodeApi.post(ENDPOINTS.COMMENT_ON_OFF, data),

  // Comments
  postComment: (data) => nodeApi.post(ENDPOINTS.POST_COMMENT, data),
  getComments: (params) => nodeApi.get(ENDPOINTS.GET_COMMENTS, { params }),
  deleteComment: (data) => nodeApi.post(ENDPOINTS.DELETE_COMMENT, data),
  editComment: (data) => nodeApi.post(ENDPOINTS.EDIT_COMMENT, data),
};

export default postService;
