import React, { useState, useRef, useEffect } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate, useLocation, Link } from 'react-router-dom';
import { logoutUser } from '../../redux/thunks/authThunks';
import './Navbar.css';

const Navbar = () => {
  const { isAuthenticated, user } = useSelector((state) => state.auth);
  const { unreadCount: chatUnread } = useSelector((state) => state.chat);
  const { unreadCount: notifUnread } = useSelector((state) => state.notifications);
  const [menuOpen, setMenuOpen] = useState(false);
  const [profileMenuOpen, setProfileMenuOpen] = useState(false);
  const profileRef = useRef(null);
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();

  // Hide navbar on auth pages
  const authPaths = ['/login', '/register', '/forgot-password'];
  if (authPaths.includes(location.pathname)) return null;
  if (!isAuthenticated) return null;

  const handleLogout = () => {
    dispatch(logoutUser());
    navigate('/login');
    setProfileMenuOpen(false);
  };

  const isActive = (path) => location.pathname === path;

  const navItems = [
    { path: '/', label: 'Home', icon: '🏠' },
    { path: '/friends', label: 'Friends', icon: '👥' },
    { path: '/messages', label: 'Messages', icon: '💬', badge: chatUnread },
    { path: '/notifications', label: 'Notifications', icon: '🔔', badge: notifUnread },
  ];

  return (
    <nav className="navbar">
      <div className="navbar-inner">
        <Link to="/" className="navbar-logo">
          <div className="navbar-logo-icon">FL</div>
          <span className="navbar-logo-text">FriendLinq</span>
        </Link>

        {/* Desktop nav */}
        <div className="navbar-links">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`navbar-link ${isActive(item.path) ? 'active' : ''}`}
            >
              <span className="navbar-link-icon">{item.icon}</span>
              <span className="navbar-link-label">{item.label}</span>
              {item.badge > 0 && <span className="navbar-badge">{item.badge}</span>}
            </Link>
          ))}
          <Link to="/search" className={`navbar-link ${isActive('/search') ? 'active' : ''}`}>
            <span className="navbar-link-icon">🔍</span>
            <span className="navbar-link-label">Search</span>
          </Link>
          <Link to="/create-post" className="navbar-create-btn">
            + Post
          </Link>
        </div>

        {/* Profile dropdown */}
        <div className="navbar-profile" ref={profileRef}>
          <button
            className="navbar-profile-btn"
            onClick={() => setProfileMenuOpen(!profileMenuOpen)}
          >
            {user?.imageURL ? (
              <img src={user.imageURL} alt="Profile" className="navbar-avatar" />
            ) : (
              <div className="navbar-avatar-placeholder">
                {(user?.firstName || 'U')[0].toUpperCase()}
              </div>
            )}
          </button>
          {profileMenuOpen && (
            <div className="navbar-profile-menu">
              <Link to="/profile" className="navbar-menu-item" onClick={() => setProfileMenuOpen(false)}>
                👤 My Profile
              </Link>
              <Link to="/groups" className="navbar-menu-item" onClick={() => setProfileMenuOpen(false)}>
                👥 Groups
              </Link>
              <Link to="/portfolio" className="navbar-menu-item" onClick={() => setProfileMenuOpen(false)}>
                📁 Portfolio
              </Link>
              <Link to="/settings" className="navbar-menu-item" onClick={() => setProfileMenuOpen(false)}>
                ⚙️ Settings
              </Link>
              <Link to="/support" className="navbar-menu-item" onClick={() => setProfileMenuOpen(false)}>
                ❓ Support
              </Link>
              <button className="navbar-menu-item navbar-menu-logout" onClick={handleLogout}>
                🚪 Logout
              </button>
            </div>
          )}
        </div>

        {/* Mobile hamburger */}
        <button className="navbar-hamburger" onClick={() => setMenuOpen(!menuOpen)}>
          {menuOpen ? '✕' : '☰'}
        </button>
      </div>

      {/* Mobile slide-out menu */}
      {menuOpen && (
        <div className="navbar-mobile-overlay" onClick={() => setMenuOpen(false)}>
          <div className="navbar-mobile-menu" onClick={(e) => e.stopPropagation()}>
            <div className="navbar-mobile-header">
              {user?.imageURL ? (
                <img src={user.imageURL} alt="Profile" className="navbar-mobile-avatar" />
              ) : (
                <div className="navbar-mobile-avatar-placeholder">
                  {(user?.firstName || 'U')[0].toUpperCase()}
                </div>
              )}
              <span className="navbar-mobile-name">{user?.firstName} {user?.lastName}</span>
            </div>
            {[...navItems,
              { path: '/search', label: 'Search', icon: '🔍' },
              { path: '/profile', label: 'My Profile', icon: '👤' },
              { path: '/groups', label: 'Groups', icon: '👥' },
              { path: '/portfolio', label: 'Portfolio', icon: '📁' },
              { path: '/create-post', label: 'Create Post', icon: '✏️' },
              { path: '/settings', label: 'Settings', icon: '⚙️' },
              { path: '/support', label: 'Support', icon: '❓' },
            ].map((item) => (
              <Link
                key={item.path + item.label}
                to={item.path}
                className={`navbar-mobile-link ${isActive(item.path) ? 'active' : ''}`}
                onClick={() => setMenuOpen(false)}
              >
                <span>{item.icon}</span>
                <span>{item.label}</span>
                {item.badge > 0 && <span className="navbar-badge">{item.badge}</span>}
              </Link>
            ))}
            <button className="navbar-mobile-link navbar-mobile-logout" onClick={handleLogout}>
              <span>🚪</span>
              <span>Logout</span>
            </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
