import React, { lazy, Suspense } from 'react';
import { Routes, Route } from 'react-router-dom';
import Navbar from './components/layout/Navbar';
import BottomNav from './components/layout/BottomNav';
import ProtectedRoute from './components/layout/ProtectedRoute';
import PublicRoute from './components/layout/PublicRoute';
import useInitialData from './hooks/useInitialData';
import useSocket from './hooks/useSocket';
import useIncomingCall from './hooks/useIncomingCall';
import IncomingCallOverlay from './components/calls/IncomingCallOverlay';

// Lazy-loaded pages
const Login = lazy(() => import('./pages/Login'));
const Register = lazy(() => import('./pages/Register'));
const ForgotPassword = lazy(() => import('./pages/ForgotPassword'));
const Home = lazy(() => import('./pages/Home'));
const Profile = lazy(() => import('./pages/Profile'));
const EditProfile = lazy(() => import('./pages/EditProfile'));
const UserProfile = lazy(() => import('./pages/UserProfile'));
const Friends = lazy(() => import('./pages/Friends'));
const Messages = lazy(() => import('./pages/Messages'));
const Chat = lazy(() => import('./pages/Chat'));
const Notifications = lazy(() => import('./pages/Notifications'));
const CreatePost = lazy(() => import('./pages/CreatePost'));
const Search = lazy(() => import('./pages/Search'));
const Groups = lazy(() => import('./pages/Groups'));
const GroupHome = lazy(() => import('./pages/GroupHome'));
const CreateGroup = lazy(() => import('./pages/CreateGroup'));
const Portfolio = lazy(() => import('./pages/Portfolio'));
const Marketplace = lazy(() => import('./pages/Marketplace'));
const Settings = lazy(() => import('./pages/Settings'));
const Support = lazy(() => import('./pages/Support'));
const Tutorials = lazy(() => import('./pages/Tutorials'));
const Subscriptions = lazy(() => import('./pages/Subscriptions'));
const Calls = lazy(() => import('./pages/Calls'));
const LiveStream = lazy(() => import('./pages/LiveStream'));

const Loading = () => (
  <div className="page-loading">
    <div className="page-loading-spinner"></div>
  </div>
);

function App() {
  useInitialData();
  useSocket();
  const { incomingCall, acceptCall, declineCall } = useIncomingCall();

  return (
    <div className="app">
      {incomingCall && (
        <IncomingCallOverlay
          callerName={incomingCall.callerName}
          callType={incomingCall.callType}
          onAccept={acceptCall}
          onDecline={declineCall}
        />
      )}
      <Navbar />
      <main className="main-content">
        <Suspense fallback={<Loading />}>
          <Routes>
            {/* Public routes */}
            <Route path="/login" element={<PublicRoute><Login /></PublicRoute>} />
            <Route path="/register" element={<PublicRoute><Register /></PublicRoute>} />
            <Route path="/forgot-password" element={<PublicRoute><ForgotPassword /></PublicRoute>} />

            {/* Protected routes */}
            <Route path="/" element={<ProtectedRoute><Home /></ProtectedRoute>} />
            <Route path="/profile" element={<ProtectedRoute><Profile /></ProtectedRoute>} />
            <Route path="/profile/edit" element={<ProtectedRoute><EditProfile /></ProtectedRoute>} />
            <Route path="/user/:userId" element={<ProtectedRoute><UserProfile /></ProtectedRoute>} />
            <Route path="/friends" element={<ProtectedRoute><Friends /></ProtectedRoute>} />
            <Route path="/messages" element={<ProtectedRoute><Messages /></ProtectedRoute>} />
            <Route path="/chat/:recipientId" element={<ProtectedRoute><Chat /></ProtectedRoute>} />
            <Route path="/notifications" element={<ProtectedRoute><Notifications /></ProtectedRoute>} />
            <Route path="/create-post" element={<ProtectedRoute><CreatePost /></ProtectedRoute>} />
            <Route path="/search" element={<ProtectedRoute><Search /></ProtectedRoute>} />
            <Route path="/groups" element={<ProtectedRoute><Groups /></ProtectedRoute>} />
            <Route path="/groups/create" element={<ProtectedRoute><CreateGroup /></ProtectedRoute>} />
            <Route path="/groups/:groupId" element={<ProtectedRoute><GroupHome /></ProtectedRoute>} />
            <Route path="/portfolio" element={<ProtectedRoute><Portfolio /></ProtectedRoute>} />
            <Route path="/portfolio/:userId" element={<ProtectedRoute><Portfolio /></ProtectedRoute>} />
            <Route path="/marketplace" element={<ProtectedRoute><Marketplace /></ProtectedRoute>} />
            <Route path="/settings" element={<ProtectedRoute><Settings /></ProtectedRoute>} />
            <Route path="/support" element={<ProtectedRoute><Support /></ProtectedRoute>} />
            <Route path="/tutorials" element={<ProtectedRoute><Tutorials /></ProtectedRoute>} />
            <Route path="/subscriptions" element={<ProtectedRoute><Subscriptions /></ProtectedRoute>} />
            <Route path="/calls" element={<ProtectedRoute><Calls /></ProtectedRoute>} />
            <Route path="/live/:streamId" element={<ProtectedRoute><LiveStream /></ProtectedRoute>} />
          </Routes>
        </Suspense>
      </main>
      <BottomNav />
    </div>
  );
}

export default App;
